import axios from './api';
import jwtDecode from 'jwt-decode';

const STORAGE_KEY = 'harari_admin_token';

const auth = {
  async login(email, password){
    // Try real API first, fallback to mock
    try{
      const res = await axios.post('/auth/login',{email,password});
      if(res?.data?.token){
        localStorage.setItem(STORAGE_KEY,res.data.token);
        return {ok:true};
      }
      return {ok:false,message:'Invalid response'};
    }catch(err){
      // fallback demo credentials
      if(email==='admin@harari.test' && password==='Admin123!'){
        // create a fake token payload
        const fake = {sub:'1',email,role:'admin',exp: Math.floor(Date.now()/1000)+60*60};
        const token = btoa(JSON.stringify(fake));
        localStorage.setItem(STORAGE_KEY,token);
        return {ok:true, demo:true};
      }
      return {ok:false,message: err?.response?.data?.message || err.message};
    }
  },
  logout(){
    localStorage.removeItem(STORAGE_KEY);
  },
  getToken(){
    return localStorage.getItem(STORAGE_KEY);
  },
  getProfile(){
    const token = auth.getToken();
    if(!token) return null;
    try{
      // try real jwt decode
      try{
        return jwtDecode(token);
      }catch(e){
        // fallback for our base64 fake
        const decoded = JSON.parse(atob(token));
        return decoded;
      }
    }catch(err){
      return null;
    }
  },
  isExpired(){
    const profile = auth.getProfile();
    if(!profile || !profile.exp) return true;
    return profile.exp * 1000 < Date.now();
  }
}

export default auth;
